    const MOD = 10**9 + 7;
    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // For each y-coordinate, process the x-values
    for (const [y, xs] of yMap.entries()) {
        const m = xs.length;
        if (m < 2) continue;

        // Sort x-values for easier processing
        xs.sort((a, b) => a - b);

        // Count the number of pairs of points at the same y-coordinate
        let sameYCount = 0;
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                if (xs[i] === xs[j]) {
                    sameYCount++;
                }
            }
        }

        // For each pair of points at the same y-coordinate, find pairs at another y-coordinate
        // that form a horizontal trapezoid
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                if (xs[i] === xs[j]) {
                    continue;
                }

                // Find the number of pairs of points at other y-coordinates
                for (const [otherY, otherXs] of yMap.entries()) {
                    if (otherY === y) continue;

                    // Count the number of pairs of points at otherY
                    let otherSameYCount = 0;
                    for (let k = 0; k < otherXs.length; k++) {
                        for (let l = k + 1; l < otherXs.length; l++) {
                            if (otherXs[k] === otherXs[l]) {
                                otherSameYCount++;
                            }
                        }
                    }

                    // Calculate the number of horizontal trapezoids formed with this pair and other pairs
                    // Each pair at y and otherY contributes to a trapezoid
                    result = (result + sameYCount * otherSameYCount) % MOD;
                }
            }
        }
    }

    return result;
}

